import React, { useState } from 'react';
import { Product, ProductVariant } from '../types';
import { COLOR_MAP } from '../constants';

interface ProductDetailViewProps {
  product: Product;
  onAddToCart: (p: Product, variantSku: string, quantity: number) => void;
  onBack: () => void;
}

const ProductDetailView: React.FC<ProductDetailViewProps> = ({ product, onAddToCart, onBack }) => {
  const [selectedVariant, setSelectedVariant] = useState<ProductVariant>(product.variants[0]);
  const [quantity, setQuantity] = useState(1);
  const [isAdded, setIsAdded] = useState(false);

  const itemTotal = (selectedVariant.price * quantity).toFixed(2);

  const handleAdd = () => {
    onAddToCart(product, selectedVariant.sku, quantity);
    setIsAdded(true);
    setTimeout(() => setIsAdded(false), 2000);
  };

  return (
    <div className="max-w-[1280px] mx-auto px-4 py-8 animate-in fade-in zoom-in-95 duration-500">
      <nav className="mb-8">
        <button onClick={onBack} className="flex items-center text-[10px] font-black text-[#86868B] uppercase tracking-[0.4em] hover:text-black transition-all group">
          <span className="material-icons text-lg mr-3 group-hover:-translate-x-1 transition-transform">arrow_back</span> Regresar
        </button>
      </nav>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 lg:gap-12 bg-white rounded-[40px] border border-black/5 p-8 md:p-12 shadow-xl">

        {/* Galería Técnica compacta */}
        <div className="lg:col-span-5 flex items-center justify-center bg-[#F5F5F7] rounded-[32px] p-10 min-h-[400px] border border-black/5 shadow-inner">
          {selectedVariant.image ? (
            <img 
              src={selectedVariant.image} 
              alt={selectedVariant.sku} 
              className="max-w-full max-h-[400px] object-contain mix-blend-multiply transition-all duration-500 hover:scale-105"
            />
          ) : (
            <div className="flex flex-col items-center text-gray-300">
              <span className="material-icons text-[80px] mb-6">inventory_2</span>
              <span className="text-[10px] font-black uppercase tracking-[0.4em]">Visual no disponible</span>
            </div>
          )}
        </div>

        {/* Configuración de Pedido */}
        <div className="lg:col-span-7 flex flex-col justify-between">
          <div>
            <header className="mb-8 pb-8 border-b border-black/5">
              <div className="text-[10px] font-black text-link-blue uppercase tracking-[0.4em] mb-3">
                {product.category} • {product.type}
              </div>
              <h1 className="text-4xl md:text-5xl font-black text-black tracking-tighter uppercase leading-tight mb-6">
                {product.title}
              </h1>
              <p className="text-base text-gray-500 font-medium uppercase tracking-tight leading-relaxed max-w-xl opacity-80">
                {product.description}
              </p>
            </header>

            {/* Selector de SKU Avanzado compactado */}
            <div className="mb-10">
              <div className="flex justify-between items-end mb-6">
                <div>
                  <h3 className="text-[10px] font-black text-black uppercase tracking-[0.4em] mb-1">Variantes Agrupadas</h3>
                  <div className="text-[9px] font-bold text-gray-400 uppercase tracking-widest">Selecciona SKU para la orden</div>
                </div>
                <div className="text-right">
                  <span className="text-[9px] font-mono font-black text-black bg-black/5 px-4 py-1.5 rounded-full border border-black/5 uppercase">
                    SKU: {selectedVariant.sku}
                  </span>
                </div>
              </div>

              <div className="grid grid-cols-2 sm:grid-cols-3 md:grid-cols-4 lg:grid-cols-5 gap-3 max-h-[250px] overflow-y-auto pr-2 custom-scrollbar">
                {product.variants.map((v) => (
                  <button 
                    key={v.sku}
                    onClick={() => setSelectedVariant(v)}
                    className={`flex flex-col items-center gap-2 p-3 rounded-2xl border-2 transition-all duration-200 ${
                      selectedVariant.sku === v.sku 
                        ? 'border-black bg-black text-white shadow-md' 
                        : 'border-black/5 hover:border-black/20 bg-white text-black'
                    }`}
                  >
                    <div 
                      className="w-6 h-6 rounded-full border border-black/10"
                      style={{ backgroundColor: COLOR_MAP[v.option1] || '#CCC' }}
                    />
                    <div className="text-center">
                      <div className="text-[8px] font-black uppercase tracking-tight leading-none mb-0.5 truncate w-full max-w-[80px]">{v.option1}</div>
                      <div className={`text-[7px] font-mono ${selectedVariant.sku === v.sku ? 'text-gray-400' : 'text-gray-300'}`}>{v.sku}</div>
                    </div>
                  </button>
                ))}
              </div>
            </div>
          </div>

          {/* Acción Maestro compactado */}
          <div className="bg-[#1D1D1F] rounded-[32px] p-8 text-white shadow-xl">
            <div className="flex flex-col md:flex-row items-center justify-between gap-8 mb-8">
              <div className="w-full md:w-48">
                <div className="text-[9px] font-black text-gray-500 uppercase tracking-[0.4em] mb-4">Cantidad</div>
                <div className="flex items-center bg-white/5 rounded-2xl border border-white/10 h-14 px-2 transition-all hover:bg-white/10">
                  <button onClick={() => setQuantity(q => Math.max(1, q - 1))} className="w-10 h-10 flex items-center justify-center hover:bg-white/10 rounded-xl transition-all">
                    <span className="material-icons text-xl">remove</span>
                  </button>
                  <input 
                    type="number" 
                    className="flex-1 bg-transparent border-none text-center font-black text-xl focus:ring-0 text-white p-0" 
                    value={quantity}
                    onChange={(e) => setQuantity(Math.max(1, parseInt(e.target.value) || 1))}
                  />
                  <button onClick={() => setQuantity(q => q + 1)} className="w-10 h-10 flex items-center justify-center hover:bg-white/10 rounded-xl transition-all">
                    <span className="material-icons text-xl">add</span>
                  </button>
                </div>
              </div>

              <div className="text-right w-full md:w-auto flex-1 md:border-l border-white/10 md:pl-10">
                <span className="text-[9px] font-black text-gray-500 uppercase tracking-[0.4em] block mb-2">Total SKU</span>
                <div className="text-4xl font-black tracking-tighter text-white leading-none">
                  ${itemTotal}
                </div>
              </div>
            </div>

            <button 
              onClick={handleAdd}
              className={`w-full h-16 rounded-2xl font-black text-xs uppercase tracking-[0.4em] transition-all flex items-center justify-center gap-4 ${
                isAdded ? 'bg-accent-green text-white scale-[1.01]' : 'bg-white text-black hover:bg-gray-100 active:scale-95 shadow-lg'
              }`}
            >
              <span className="material-icons text-xl">{isAdded ? 'done' : 'add_shopping_cart'}</span>
              {isAdded ? 'Añadido' : 'Cargar a Proforma'}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ProductDetailView;

import React from 'react';
import { CartItem } from '../types';

interface ReviewOrderViewProps {
  cart: CartItem[];
  onUpdateQuantity: (sku: string, qty: number) => void;
  onRemove: (sku: string) => void;
  onBack: () => void;
  onConfirm: () => void;
}

const ReviewOrderView: React.FC<ReviewOrderViewProps> = ({ cart, onUpdateQuantity, onRemove, onBack, onConfirm }) => {
  const subtotal = cart.reduce((acc, curr) => acc + (curr.variant.price * curr.quantity), 0);
  const tax = subtotal * 0.07;
  const total = subtotal + tax;

  const buildOrderText = () => {
    const br = "\n";
    let text = `📦 *ORDEN B2B CUBITT PANAMA*${br}${br}`;
    cart.forEach((item, i) => {
      text += `${i+1}. *${item.product.title}*${br}   SKU: \`${item.variant.sku}\` | Cant: ${item.quantity}${br}${br}`;
    });
    text += `*TOTAL FINAL: $${total.toFixed(2)}*${br}${br}ID: ${Date.now().toString().slice(-6)}`;
    return text;
  };

  const handleWhatsApp = () => {
    window.open(`https://wa.me/50761541129?text=${encodeURIComponent(buildOrderText())}`, '_blank');
    onConfirm();
  };

  const handleEmail = () => {
    const subject = encodeURIComponent("Orden Mayorista Cubitt - " + new Date().toLocaleDateString());
    const body = encodeURIComponent(buildOrderText());
    window.location.href = `mailto:ventas@cubitt.com?subject=${subject}&body=${body}`;
    onConfirm();
  };

  if (cart.length === 0) {
    return (
      <div className="max-w-2xl mx-auto px-4 py-24 text-center">
        <span className="material-icons text-[80px] text-gray-200 mb-8">receipt_long</span>
        <h2 className="text-xl font-black uppercase tracking-[0.4em] mb-10">Sin SKUs Cargados</h2>
        <button onClick={onBack} className="bg-black text-white px-10 py-4 rounded-full text-xs font-black uppercase tracking-[0.2em] shadow-lg hover:scale-105 transition-all">
          Explorar Catálogo
        </button>
      </div>
    );
  }

  return (
    <div className="max-w-[1280px] mx-auto px-4 py-10 animate-in fade-in duration-500">
      <div className="flex flex-col md:flex-row justify-between items-end mb-12 gap-8">
        <div>
          <button onClick={onBack} className="text-[10px] font-black text-gray-400 uppercase tracking-[0.4em] mb-4 flex items-center gap-2 hover:text-black group">
            <span className="material-icons text-base group-hover:-translate-x-1 transition-transform">west</span> Regresar
          </button>
          <h1 className="text-4xl md:text-5xl font-black text-black uppercase tracking-tighter leading-none">Mi Proforma</h1>
        </div>
        <div className="bg-black text-white px-8 py-5 rounded-[24px] flex items-center gap-6 shadow-xl">
          <div className="text-right">
            <div className="text-[9px] font-black uppercase tracking-widest opacity-40 mb-1">Líneas SKU</div>
            <div className="text-2xl font-black leading-none">{cart.length}</div>
          </div>
          <div className="w-px h-10 bg-white/20" />
          <span className="material-icons text-3xl">inventory</span>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
        <div className="lg:col-span-8">
          <div className="bg-white rounded-[32px] border border-black/5 overflow-hidden shadow-sm">
            <table className="w-full text-left">
              <thead className="bg-[#F5F5F7] text-[9px] font-black text-gray-400 uppercase tracking-[0.3em] border-b border-black/5">
                <tr>
                  <th className="px-8 py-6">Producto / SKU</th>
                  <th className="px-8 py-6 text-center w-32">Cant</th>
                  <th className="px-8 py-6 text-right">Monto</th>
                </tr>
              </thead>
              <tbody className="divide-y divide-black/5">
                {cart.map(item => (
                  <tr key={item.variant.sku} className="group hover:bg-[#F5F5F7]/40 transition-colors">
                    <td className="px-8 py-6">
                      <div className="flex items-center gap-6">
                        <div className="w-14 h-14 bg-[#F5F5F7] rounded-2xl p-2 border border-black/5 shrink-0 flex items-center justify-center shadow-inner">
                          {item.variant.image ? <img src={item.variant.image} className="max-h-full object-contain mix-blend-multiply" /> : <span className="material-icons text-xl text-gray-300">image</span>}
                        </div>
                        <div>
                          <div className="text-base font-black text-black uppercase tracking-tight leading-none mb-2">{item.product.title}</div>
                          <div className="flex items-center gap-3">
                            <span className="text-[10px] font-bold text-gray-500 uppercase tracking-widest">{item.variant.option1}</span>
                            <span className="text-gray-300">|</span>
                            <span className="text-[10px] font-mono text-black font-black bg-black/5 px-2 py-0.5 rounded-md uppercase">{item.variant.sku}</span>
                          </div>
                        </div>
                      </div>
                    </td>
                    <td className="px-8 py-6">
                      <div className="flex items-center bg-white border border-black/10 rounded-xl h-10 w-24 mx-auto overflow-hidden shadow-inner px-2">
                        <button onClick={() => onUpdateQuantity(item.variant.sku, item.quantity - 1)} className="flex-1 hover:bg-gray-100 font-bold">-</button>
                        <span className="w-8 text-center font-black text-sm">{item.quantity}</span>
                        <button onClick={() => onUpdateQuantity(item.variant.sku, item.quantity + 1)} className="flex-1 hover:bg-gray-100 font-bold">+</button>
                      </div>
                    </td>
                    <td className="px-8 py-6 text-right">
                      <div className="text-xl font-black text-black tracking-tighter">${(item.variant.price * item.quantity).toFixed(2)}</div>
                      <button onClick={() => onRemove(item.variant.sku)} className="text-[8px] text-red-500 font-black uppercase mt-2 opacity-0 group-hover:opacity-100 transition-opacity underline underline-offset-2">Quitar</button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </div>

        <div className="lg:col-span-4">
          <div className="bg-white rounded-[32px] border border-black/5 p-8 md:p-10 sticky top-20 shadow-xl shadow-black/5">
            <h2 className="text-[10px] font-black text-black uppercase tracking-[0.4em] mb-10 border-b border-black/5 pb-6 text-center">Resumen B2B</h2>

            <div className="space-y-6 mb-10">
              <div className="flex justify-between text-[10px] font-black uppercase tracking-widest text-gray-400">
                <span>Subtotal</span>
                <span className="text-black">${subtotal.toFixed(2)}</span>
              </div>
              <div className="flex justify-between text-[10px] font-black uppercase tracking-widest text-gray-400">
                <span>ITBMS (7%)</span>
                <span className="text-black">${tax.toFixed(2)}</span>
              </div>
              <div className="pt-8 border-t border-black/5 text-right">
                <div className="text-[10px] font-black text-gray-400 uppercase tracking-[0.4em] mb-4">Total Orden</div>
                <div className="text-5xl font-black text-black tracking-tighter leading-none">${total.toFixed(2)}</div>
              </div>
            </div>

            <div className="space-y-4">
              <button 
                onClick={handleWhatsApp}
                className="w-full h-16 bg-black text-white rounded-[20px] text-[10px] font-black uppercase tracking-[0.4em] hover:bg-[#1D1D1F] active:scale-[0.98] transition-all flex items-center justify-center gap-4 shadow-lg group"
              >
                <span className="material-icons text-xl group-hover:scale-110 transition-transform">chat</span>
                Confirmar WhatsApp
              </button>

              <button 
                onClick={handleEmail}
