  price: number;
  compareAtPrice?: number;
  inventory: number;
  image: string;
  isBestSeller?: boolean;
  isSale?: boolean;
  tags?: string;
}

export const transformRawData = (records: RawRecord[]): Product[] => {
  const productMap: Record<string, Product> = {};

  records.forEach(rec => {
    if (!productMap[rec.handle]) {
      productMap[rec.handle] = {
        id: rec.handle,
        handle: rec.handle,
        title: rec.title,
        description: rec.description,
        vendor: rec.vendor || 'Cubitt',
        category: rec.category || rec.type,
        type: rec.type,
        mainImage: rec.image,
        tags: rec.tags ? rec.tags.split(',') : [],
        isBestSeller: rec.isBestSeller,
        isSale: rec.isSale,
        variants: [],
        isOutOfStock: false, // Se calculará después
      };
    }

    const variant: ProductVariant = {
      sku: rec.sku,
      option1: rec.color,
      price: rec.price,
      compareAtPrice: rec.compareAtPrice,
      inventory: rec.inventory,
      image: rec.image
    };

    productMap[rec.handle].variants.push(variant);
  });

  // Post-procesamiento: calcular si está fuera de stock globalmente
  return Object.values(productMap).map(product => {
    const totalStock = product.variants.reduce((acc, v) => acc + v.inventory, 0);
