import { Product, ProductVariant } from '../types';
import Papa from 'papaparse';

// Definición flexible de las columnas esperadas en el CSV
interface CsvRow {
  Handle: string;
  Title: string;
  Description: string;
  Vendor?: string;
  Type: string;
  Category?: string; // Opcional, si no existe usa Type
  SKU: string;
  Color: string; // O Option1 Name
  Price: string | number;
  CompareAtPrice?: string | number;
  Inventory: string | number;
  Image: string;
  Tags?: string;
  [key: string]: any; // Permitir otras columnas
}

export const parseCSVToProducts = (csvText: string): Promise<Product[]> => {
  return new Promise((resolve, reject) => {
    Papa.parse(csvText, {
      header: true,
      skipEmptyLines: true,
      complete: (results) => {
        const rows = results.data as CsvRow[];
        const productMap: Record<string, Product> = {};

        rows.forEach((row) => {
          // Normalización básica de datos
          const handle = row.Handle?.trim();
          if (!handle) return;

          // Convertir precios e inventario a números seguros
          const price = parseFloat(String(row.Price || '0').replace(/[^0-9.]/g, '')) || 0;
          const comparePrice = row.CompareAtPrice ? parseFloat(String(row.CompareAtPrice).replace(/[^0-9.]/g, '')) : undefined;
          const inventory = parseInt(String(row.Inventory || '0'), 10) || 0;

          // Si el producto no existe en el mapa, crearlo
          if (!productMap[handle]) {
            productMap[handle] = {
              id: handle,
              handle: handle,
              title: row.Title || 'Sin Título',
              description: row.Description || '',
              vendor: row.Vendor || 'Cubitt',
              category: row.Category || row.Type || 'General',
              type: row.Type || 'General',
              mainImage: row.Image || '',
              tags: row.Tags ? row.Tags.split(',').map(t => t.trim()) : [],
              variants: [],
              isOutOfStock: false,
              isBestSeller: (row.Tags || '').toLowerCase().includes('best seller') || (row.Tags || '').toLowerCase().includes('popular'),
              isSale: (row.Tags || '').toLowerCase().includes('sale') || !!comparePrice,
            };
          }

          // Crear la variante
          const variant: ProductVariant = {
            sku: row.SKU || `${handle}-${row.Color || 'Default'}`,
            option1: row.Color || 'Default',
            price: price,
            compareAtPrice: comparePrice,
            inventory: inventory,
            image: row.Image || productMap[handle].mainImage
          };

          productMap[handle].variants.push(variant);
        });

        // Post-procesamiento: Calcular stock global y limpiar datos
        const products = Object.values(productMap).map(product => {
          // Si no hay imagen principal definida, usar la de la primera variante
          if (!product.mainImage && product.variants.length > 0) {
            product.mainImage = product.variants[0].image;
          }

          const totalStock = product.variants.reduce((acc, v) => acc + v.inventory, 0);
          return {
            ...product,
            isOutOfStock: totalStock <= 0,
            restockingSoon: totalStock <= 10 && totalStock > 0
          };
        });

        resolve(products);
      },
      error: (error: any) => {
        reject(error);
      }
    });
  });
};

export const fetchProductsFromUrl = async (url: string): Promise<Product[]> => {
  try {
    const response = await fetch(url);
    if (!response.ok) throw new Error('Error al descargar el CSV');
    const text = await response.text();
    return parseCSVToProducts(text);
  } catch (error) {
    console.error("Error fetching CSV:", error);
    throw error;
  }
};

import React, { useState, useRef } from 'react';
import { Category, Product } from '../types';

interface SidebarProps {
  products: Product[];
  selectedCategory: Category;
  setSelectedCategory: (c: Category) => void;
  inStockOnly: boolean;
  setInStockOnly: (val: boolean) => void;
  onDataUpdate?: (products: Product[]) => void; // Callback opcional para actualizar datos
  onResetData?: () => void;
}

// Helper para leer archivo local
const readFileAsText = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => resolve(e.target?.result as string);
    reader.onerror = (e) => reject(e);
    reader.readAsText(file);
  });
};

const Sidebar: React.FC<SidebarProps> = ({ 
  products, 
  selectedCategory, 
  setSelectedCategory, 
  inStockOnly, 
  setInStockOnly,
  onDataUpdate,
  onResetData
}) => {
  const [sheetUrl, setSheetUrl] = useState('');
  const [loading, setLoading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  // Extraer tipos únicos de los productos dinámicamente
  const types: string[] = Array.from(new Set(products.map(p => p.type))).sort();

  const getIcon = (type: string) => {
    switch (type.toLowerCase()) {
      case 'smartwatches': return 'watch';
      case 'bocinas': return 'speaker';
      case 'básculas': return 'monitor_weight';
      case 'audífonos': return 'headphones';
      case 'teens': return 'face';
      case 'accesorios': return 'widgets';
      case 'hidratación': return 'water_drop';
      case 'termos': return 'water_drop';
      default: return 'label';
    }
  };

  const handleUrlSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!sheetUrl || !onDataUpdate) return;

    setLoading(true);
    try {
      // Importación dinámica para evitar ciclos si dataService importa types
      const { fetchProductsFromUrl } = await import('../services/dataService');
      const newProducts = await fetchProductsFromUrl(sheetUrl);
      onDataUpdate(newProducts);
      alert(`Catálogo actualizado: ${newProducts.length} productos cargados.`);
    } catch (err) {
      alert('Error al cargar desde Google Sheets. Asegúrate de que el enlace sea "Publicar en la web -> CSV".');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !onDataUpdate) return;

    setLoading(true);
    try {
      const text = await readFileAsText(file);
      const { parseCSVToProducts } = await import('../services/dataService');
      const newProducts = await parseCSVToProducts(text);
      onDataUpdate(newProducts);
      alert(`Catálogo local cargado: ${newProducts.length} productos.`);
    } catch (err) {
      alert('Error al leer el archivo CSV.');
      console.error(err);
    } finally {
      setLoading(false);
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  return (
    <aside className="w-64 flex-shrink-0 hidden lg:flex flex-col sticky top-20 h-[calc(100vh-6rem)]">
      <div className="flex-1 overflow-y-auto pr-2 custom-scrollbar">
        <div className="mb-8">
          <h3 className="text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4 px-3">Categorías</h3>
          <ul className="space-y-1">
            <li>
              <button
                onClick={() => setSelectedCategory('All')}
                className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all ${
                  selectedCategory === 'All' 
                    ? 'bg-black text-white shadow-md scale-[1.02]' 
                    : 'text-gray-600 hover:bg-white hover:text-black font-medium'
                }`}
              >
                <span className="material-symbols-outlined text-lg">dashboard</span>
                <span className="text-sm">Todo el Catálogo</span>
              </button>
            </li>
            {types.map(type => (
              <li key={type}>
                <button
                  onClick={() => setSelectedCategory(type)}
                  className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all ${
                    selectedCategory === type 
                      ? 'bg-black text-white shadow-md scale-[1.02]' 
                      : 'text-gray-600 hover:bg-white hover:text-black font-medium'
                  }`}
                >
                  <span className="material-symbols-outlined text-lg">{getIcon(type)}</span>
                  <span className="text-sm">{type}</span>
                </button>
              </li>
            ))}
          </ul>
        </div>

        <div className="mb-8">
          <h3 className="text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4 px-3">Filtros</h3>
          <div 
            className="flex items-center gap-3 cursor-pointer group px-3 py-2 bg-white rounded-xl border border-black/5" 
            onClick={() => setInStockOnly(!inStockOnly)}
          >
            <div className={`w-4 h-4 rounded border flex items-center justify-center transition-all ${inStockOnly ? 'bg-black border-black' : 'border-gray-300'}`}>
              {inStockOnly && <span className="material-icons text-[10px] text-white">done</span>}
            </div>
            <label className="text-sm text-gray-600 group-hover:text-black transition-colors cursor-pointer font-medium">Solo en Stock</label>
          </div>
        </div>

        {/* Sección de Administración de Datos */}
        <div className="mb-8 pt-6 border-t border-black/5">
          <h3 className="text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4 px-3 flex items-center gap-2">
            <span className="material-icons text-sm">database</span>
            Data Source
          </h3>

          <form onSubmit={handleUrlSubmit} className="px-3 mb-4">
            <input 
              type="url" 
              placeholder="Google Sheet CSV Link" 
              className="w-full text-[10px] p-2 rounded-lg border border-gray-200 mb-2 bg-white focus:ring-1 focus:ring-black"
              value={sheetUrl}
              onChange={(e) => setSheetUrl(e.target.value)}
            />
            <button 
              type="submit" 
              disabled={loading}
              className="w-full bg-black text-white text-[10px] font-bold py-2 rounded-lg hover:bg-gray-800 disabled:opacity-50 transition-colors"
            >
              {loading ? 'Cargando...' : 'Sync Google Sheet'}
            </button>
          </form>

          <div className="px-3">
             <button 
              onClick={() => fileInputRef.current?.click()}
              disabled={loading}
              className="w-full bg-white border border-gray-200 text-black text-[10px] font-bold py-2 rounded-lg hover:bg-gray-50 disabled:opacity-50 transition-colors mb-2"
            >
              Cargar CSV Local
            </button>
            <input 
              type="file" 
              accept=".csv" 
              ref={fileInputRef} 
              className="hidden" 
              onChange={handleFileUpload}
            />

            {onResetData && (
              <button 
                onClick={onResetData}
                className="w-full text-red-500 text-[9px] font-bold py-1 hover:underline"
              >
                Resetear a Demo Data
              </button>
            )}
          </div>

          <p className="px-3 mt-3 text-[9px] text-gray-400 leading-tight">
            Formato: Handle, Title, Description, Type, SKU, Color, Price, Inventory, Image.
          </p>
        </div>
      </div>
    </aside>
  );
};

