import ReviewOrderView from './components/ReviewOrderView';
import AccountView from './components/AccountView';
import Login from './components/Login';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  // Estado de productos ahora es dinámico, inicializado con constants.ts
  const [products, setProducts] = useState<Product[]>(PRODUCTS);
  const [cart, setCart] = useState<CartItem[]>([]);
  const [selectedCategory, setSelectedCategory] = useState<Category>('All');
  const [searchQuery, setSearchQuery] = useState('');
  const [inStockOnly, setInStockOnly] = useState(false);
  const [currentView, setCurrentView] = useState<AppView>('CATALOG');
  const [activeProduct, setActiveProduct] = useState<Product | null>(null);

  const filteredProducts = useMemo(() => {
    return products.filter(p => {
      const matchesCategory = selectedCategory === 'All' || p.type === selectedCategory;
      const matchesSearch = p.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
                           p.variants.some(v => v.sku.toLowerCase().includes(searchQuery.toLowerCase()));
      const matchesStock = inStockOnly ? !p.isOutOfStock : true;
      return matchesCategory && matchesSearch && matchesStock;
    });
  }, [products, selectedCategory, searchQuery, inStockOnly]);

  const cartTotal = cart.reduce((acc, curr) => acc + (curr.variant.price * curr.quantity), 0);
  const cartCount = cart.reduce((acc, curr) => acc + curr.quantity, 0);

  const handleLogin = (u: User) => {
    setUser(u);
    setCurrentView('CATALOG');
  };

  const handleProductSelect = (p: Product) => {
    setActiveProduct(p);
    setCurrentView('PRODUCT_DETAIL');
  };

  const handleAddToCart = (product: Product, variantSku: string, quantity: number) => {
    const variant = product.variants.find(v => v.sku === variantSku)!;
    setCart(prev => {
      const existingIndex = prev.findIndex(item => item.variant.sku === variantSku);
      if (existingIndex > -1) {
        const newCart = [...prev];
        newCart[existingIndex].quantity += quantity;
        return newCart;
      }
      return [...prev, { product, variant, quantity }];
    });
  };

  const removeFromCart = (sku: string) => {
    setCart(prev => prev.filter(item => item.variant.sku !== sku));
  };

  const updateCartQuantity = (sku: string, qty: number) => {
    setCart(prev => prev.map(item => item.variant.sku === sku ? { ...item, quantity: Math.max(1, qty) } : item));
  };

  const navigateTo = (view: AppView) => {
    setCurrentView(view);
    if (view !== 'PRODUCT_DETAIL') setActiveProduct(null);
    window.scrollTo(0,0);
  };

  // Manejadores de Data Source
  const handleDataUpdate = (newProducts: Product[]) => {
    setProducts(newProducts);
    setSelectedCategory('All'); // Resetear filtro para evitar categorías fantasmas
  };

  const handleResetData = () => {
    setProducts(PRODUCTS);
    setSelectedCategory('All');
    alert('Catálogo restaurado a datos de demostración.');
  };

  if (!user) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen bg-[#F5F5F7] text-[#1D1D1F] flex flex-col font-sans transition-colors duration-200">
      <Navbar 
        user={user} 
        cartCount={cartCount}
        onOpenCart={() => navigateTo('REVIEW_ORDER')}
        onNavigate={navigateTo}
        searchQuery={searchQuery}
        setSearchQuery={setSearchQuery}
      />

      {currentView === 'CATALOG' && (
        <div className="max-w-[1440px] mx-auto px-6 py-8 flex gap-8 w-full">
          <Sidebar 
            products={products}
            selectedCategory={selectedCategory} 
            setSelectedCategory={setSelectedCategory} 
            inStockOnly={inStockOnly}
            setInStockOnly={setInStockOnly}
            onDataUpdate={handleDataUpdate}
            onResetData={handleResetData}
          />

          <ProductGrid 
            products={filteredProducts} 
            onSelect={handleProductSelect} 
            selectedCategory={selectedCategory}
          />
        </div>
      )}

      {currentView === 'PRODUCT_DETAIL' && activeProduct && (
        <ProductDetailView 
          product={activeProduct} 
          onAddToCart={handleAddToCart}
          onBack={() => navigateTo('CATALOG')}
          onViewOrder={() => navigateTo('REVIEW_ORDER')}
        />
      )}

      {currentView === 'REVIEW_ORDER' && (
        <ReviewOrderView 
          cart={cart} 
          onUpdateQuantity={updateCartQuantity}
          onRemove={removeFromCart}
          onBack={() => navigateTo('CATALOG')}
          onConfirm={() => {
            setCart([]);
            navigateTo('CATALOG');
          }}
        />
      )}

      {currentView === 'ACCOUNT' && (
        <AccountView user={user} onBack={() => navigateTo('CATALOG')} />
      )}

      {currentView === 'CATALOG' && cart.length > 0 && (
        <div className="fixed bottom-8 right-8 z-40 animate-bounce-in">
          <div 
            onClick={() => navigateTo('REVIEW_ORDER')}
            className="bg-black text-white px-6 py-4 rounded-full shadow-2xl flex items-center gap-4 hover:scale-105 transition-transform cursor-pointer"
          >
            <div className="relative">
              <span className="material-icons text-white text-2xl">shopping_bag</span>
              <span className="absolute -top-1 -right-1 w-4 h-4 bg-white text-black text-[10px] font-bold rounded-full flex items-center justify-center">
                {cartCount}
              </span>
            </div>
            <div className="flex flex-col text-left">
              <span className="text-[10px] uppercase tracking-wider text-gray-300 font-semibold">Current Order</span>
              <span className="text-xl font-bold leading-none">${cartTotal.toFixed(2)}</span>
            </div>
            <span className="material-icons text-gray-400">chevron_right</span>
          </div>
        </div>
      )}

      <footer className="bg-white border-t border-[#E5E5E5] mt-auto">
        <div className="max-w-7xl mx-auto px-6 py-8 flex flex-col md:flex-row justify-between items-center gap-4">
          <div className="text-[10px] font-bold text-[#86868B] uppercase tracking-[0.2em]">
            © 2024 Cubitt Panama. Portal Corporativo B2B.
          </div>
          <div className="flex gap-8 text-[10px] font-bold text-[#86868B] uppercase tracking-[0.2em]">
            <a className="hover:text-black transition-colors" href="#">Privacidad</a>
            <a className="hover:text-black transition-colors" href="#">Términos B2B</a>
          </div>
        </div>
      </footer>
    </div>
  );
};

export default App;

import { Product, ProductVariant } from '../types';
import Papa from 'papaparse';
import * as XLSX from 'xlsx';

// Definición flexible de las columnas esperadas
interface DataRow {
  Handle?: string;
  Title?: string;
  Description?: string;
  Vendor?: string;
  Type?: string;
  Category?: string;
  SKU?: string;
  Color?: string;
  'Option1 Value'?: string; // Alternativa comun en Shopify
  Price?: string | number;
  'Variant Price'?: string | number; // Alternativa
  CompareAtPrice?: string | number;
  Inventory?: string | number;
  'Variant Inventory Qty'?: string | number; // Alternativa
  Image?: string;
  'Image Src'?: string; // Alternativa
  Tags?: string;
  [key: string]: any;
}

// Lógica central de mapeo (usada por CSV y Excel)
const processRawRows = (rows: DataRow[]): Product[] => {
  const productMap: Record<string, Product> = {};

  rows.forEach((row) => {
    // Normalización de campos clave
    const handle = row.Handle?.trim();
    if (!handle) return;

    const priceRaw = row.Price || row['Variant Price'] || '0';
    const price = parseFloat(String(priceRaw).replace(/[^0-9.]/g, '')) || 0;

    const comparePriceRaw = row.CompareAtPrice;
    const comparePrice = comparePriceRaw ? parseFloat(String(comparePriceRaw).replace(/[^0-9.]/g, '')) : undefined;

    const inventoryRaw = row.Inventory || row['Variant Inventory Qty'] || '0';
    const inventory = parseInt(String(inventoryRaw), 10) || 0;

    const image = row.Image || row['Image Src'] || '';
    const color = row.Color || row['Option1 Value'] || 'Default';

    // Si el producto no existe en el mapa, crearlo
    if (!productMap[handle]) {
      productMap[handle] = {
        id: handle,
        handle: handle,
        title: row.Title || 'Sin Título',
        description: row.Description || '',
        vendor: row.Vendor || 'Cubitt',
        category: row.Category || row.Type || 'General',
        type: row.Type || 'General',
        mainImage: image,
        tags: row.Tags ? String(row.Tags).split(',').map(t => t.trim()) : [],
        variants: [],
        isOutOfStock: false,
        isBestSeller: (String(row.Tags || '')).toLowerCase().includes('best seller'),
        isSale: (String(row.Tags || '')).toLowerCase().includes('sale') || !!comparePrice,
      };
    }

    // Evitar duplicados de variantes (basado en SKU o Color si no hay SKU)
    const sku = row.SKU || `${handle}-${color.replace(/\s+/g, '')}`;
    const exists = productMap[handle].variants.some(v => v.sku === sku);

    if (!exists) {
      const variant: ProductVariant = {
        sku: sku,
        option1: color,
        price: price,
        compareAtPrice: comparePrice,
        inventory: inventory,
        image: image || productMap[handle].mainImage
      };
      productMap[handle].variants.push(variant);
    }
  });

  // Post-procesamiento
  return Object.values(productMap).map(product => {
    if (!product.mainImage && product.variants.length > 0) {
      product.mainImage = product.variants[0].image;
    }
    const totalStock = product.variants.reduce((acc, v) => acc + v.inventory, 0);
    return {
      ...product,
      isOutOfStock: totalStock <= 0,
      restockingSoon: totalStock <= 10 && totalStock > 0
    };
  });
};

export const parseCSVToProducts = (csvText: string): Promise<Product[]> => {
  return new Promise((resolve, reject) => {
    Papa.parse(csvText, {
      header: true,
      skipEmptyLines: true,
      complete: (results) => {
        try {
          const products = processRawRows(results.data as DataRow[]);
          resolve(products);
        } catch (e) {
          reject(e);
        }
      },
      error: (error: any) => reject(error)
    });
  });
};

export const parseExcelToProducts = (arrayBuffer: ArrayBuffer): Product[] => {
  const workbook = XLSX.read(arrayBuffer, { type: 'array' });
  const firstSheetName = workbook.SheetNames[0];
  const worksheet = workbook.Sheets[firstSheetName];
  // Convertir hoja a JSON (array de objetos)
  const rows = XLSX.utils.sheet_to_json(worksheet) as DataRow[];
  return processRawRows(rows);
};

export const fetchProductsFromUrl = async (url: string): Promise<Product[]> => {
  try {
    const response = await fetch(url);
    if (!response.ok) throw new Error('Error al descargar el archivo');
    const text = await response.text();
    return parseCSVToProducts(text);
  } catch (error) {
    console.error("Error fetching data:", error);
    throw error;
  }
};

import React, { useState, useRef } from 'react';
import { Category, Product } from '../types';

interface SidebarProps {
  products: Product[];
  selectedCategory: Category;
  setSelectedCategory: (c: Category) => void;
  inStockOnly: boolean;
  setInStockOnly: (val: boolean) => void;
  onDataUpdate?: (products: Product[]) => void;
  onResetData?: () => void;
}

// Helpers de lectura de archivo
const readFileAsText = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => resolve(e.target?.result as string);
    reader.onerror = (e) => reject(e);
    reader.readAsText(file);
  });
};

const readFileAsArrayBuffer = (file: File): Promise<ArrayBuffer> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => resolve(e.target?.result as ArrayBuffer);
    reader.onerror = (e) => reject(e);
    reader.readAsArrayBuffer(file);
  });
};

const Sidebar: React.FC<SidebarProps> = ({ 
  products, 
  selectedCategory, 
  setSelectedCategory, 
  inStockOnly, 
  setInStockOnly,
  onDataUpdate,
  onResetData
}) => {
  const [sheetUrl, setSheetUrl] = useState('');
  const [loading, setLoading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const types: string[] = Array.from(new Set(products.map(p => p.type))).sort();

  const getIcon = (type: string) => {
    switch (type.toLowerCase()) {
      case 'smartwatches': return 'watch';
      case 'bocinas': return 'speaker';
      case 'básculas': return 'monitor_weight';
      case 'audífonos': return 'headphones';
      case 'teens': return 'face';
      case 'accesorios': return 'widgets';
      case 'hidratación': return 'water_drop';
      case 'termos': return 'water_drop';
      default: return 'label';
    }
  };

  const handleUrlSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!sheetUrl || !onDataUpdate) return;

    setLoading(true);
    try {
      const { fetchProductsFromUrl } = await import('../services/dataService');
      const newProducts = await fetchProductsFromUrl(sheetUrl);
      if (newProducts.length === 0) throw new Error('No se encontraron productos válidos.');
      onDataUpdate(newProducts);
      alert(`Éxito: ${newProducts.length} productos cargados desde URL.`);
    } catch (err) {
      alert('Error: Asegúrate de que el enlace sea un CSV público válido.');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !onDataUpdate) return;

    setLoading(true);
    try {
      let newProducts: Product[] = [];
      const fileName = file.name.toLowerCase();

      // Importación dinámica del servicio
      const { parseCSVToProducts, parseExcelToProducts } = await import('../services/dataService');

      if (fileName.endsWith('.csv')) {
        const text = await readFileAsText(file);
        newProducts = await parseCSVToProducts(text);
      } else if (fileName.endsWith('.xlsx') || fileName.endsWith('.xls')) {
        const buffer = await readFileAsArrayBuffer(file);
        newProducts = parseExcelToProducts(buffer);
      } else {
        throw new Error('Formato no soportado. Usa .csv, .xlsx o .xls');
      }

      if (newProducts.length === 0) throw new Error('El archivo no contiene productos válidos.');

      onDataUpdate(newProducts);
      alert(`Éxito: ${newProducts.length} productos cargados desde archivo.`);
    } catch (err: any) {
      alert(`Error al procesar archivo: ${err.message || 'Formato inválido'}`);
      console.error(err);
    } finally {
      setLoading(false);
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  return (
    <aside className="w-64 flex-shrink-0 hidden lg:flex flex-col sticky top-20 h-[calc(100vh-6rem)]">
      <div className="flex-1 overflow-y-auto pr-2 custom-scrollbar">
        <div className="mb-8">
          <h3 className="text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4 px-3">Categorías</h3>
          <ul className="space-y-1">
            <li>
              <button
                onClick={() => setSelectedCategory('All')}
                className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all ${
                  selectedCategory === 'All' 
                    ? 'bg-black text-white shadow-md scale-[1.02]' 
                    : 'text-gray-600 hover:bg-white hover:text-black font-medium'
                }`}
              >
                <span className="material-symbols-outlined text-lg">dashboard</span>
                <span className="text-sm">Todo el Catálogo</span>
              </button>
            </li>
            {types.map(type => (
              <li key={type}>
                <button
                  onClick={() => setSelectedCategory(type)}
                  className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all ${
                    selectedCategory === type 
                      ? 'bg-black text-white shadow-md scale-[1.02]' 
                      : 'text-gray-600 hover:bg-white hover:text-black font-medium'
                  }`}
                >
                  <span className="material-symbols-outlined text-lg">{getIcon(type)}</span>
                  <span className="text-sm">{type}</span>
                </button>
              </li>
            ))}
          </ul>
        </div>

        <div className="mb-8">
          <h3 className="text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4 px-3">Filtros</h3>
          <div 
            className="flex items-center gap-3 cursor-pointer group px-3 py-2 bg-white rounded-xl border border-black/5" 
            onClick={() => setInStockOnly(!inStockOnly)}
          >
            <div className={`w-4 h-4 rounded border flex items-center justify-center transition-all ${inStockOnly ? 'bg-black border-black' : 'border-gray-300'}`}>
              {inStockOnly && <span className="material-icons text-[10px] text-white">done</span>}
            </div>
            <label className="text-sm text-gray-600 group-hover:text-black transition-colors cursor-pointer font-medium">Solo en Stock</label>
          </div>
        </div>

        {/* Sección de Administración de Datos */}
        <div className="mb-8 pt-6 border-t border-black/5">
          <h3 className="text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4 px-3 flex items-center gap-2">
            <span className="material-icons text-sm">database</span>
            Gestión de Datos
          </h3>

          <form onSubmit={handleUrlSubmit} className="px-3 mb-4">
            <input 
              type="url" 
              placeholder="Google Sheet CSV Link" 
              className="w-full text-[10px] p-2 rounded-lg border border-gray-200 mb-2 bg-white focus:ring-1 focus:ring-black"
              value={sheetUrl}
              onChange={(e) => setSheetUrl(e.target.value)}
            />
            <button 
              type="submit" 
              disabled={loading}
              className="w-full bg-black text-white text-[10px] font-bold py-2 rounded-lg hover:bg-gray-800 disabled:opacity-50 transition-colors"
            >
              {loading ? 'Cargando...' : 'Sincronizar G-Sheet'}
            </button>
          </form>

          <div className="px-3">
             <button 
              onClick={() => fileInputRef.current?.click()}
              disabled={loading}
              className="w-full bg-white border border-gray-200 text-black text-[10px] font-bold py-2 rounded-lg hover:bg-gray-50 disabled:opacity-50 transition-colors mb-2 flex items-center justify-center gap-2"
            >
              {loading ? 'Procesando...' : (
                <>
                  <span className="material-icons text-sm">upload_file</span>
                  Cargar CSV / Excel
                </>
              )}
            </button>
            <input 
              type="file" 
              accept=".csv, application/vnd.openxmlformats-officedocument.spreadsheetml.sheet, application/vnd.ms-excel" 
              ref={fileInputRef} 
              className="hidden" 
              onChange={handleFileUpload}
            />

            {onResetData && (
              <button 
                onClick={onResetData}
                className="w-full text-red-500 text-[9px] font-bold py-1 hover:underline text-center"
              >
                Restaurar Demo Data
              </button>
            )}
          </div>

          <p className="px-3 mt-3 text-[9px] text-gray-400 leading-tight">
            Soporta: .csv, .xlsx, .xls.<br/>
            Formato: Handle, Title, Price, SKU, Inventory, Image.
          </p>
        </div>
      </div>
    </aside>
  );
};

export default Sidebar;

import React, { useState, useMemo } from 'react';
import { User, Product, CartItem, Category, AppView } from './types';
import { PRODUCTS } from './constants';
import Navbar from './components/Navbar';
import Sidebar from './components/Sidebar';
import ProductGrid from './components/ProductGrid';
import ProductDetailView from './components/ProductDetailView';
import ReviewOrderView from './components/ReviewOrderView';
import AccountView from './components/AccountView';
import Login from './components/Login';

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(null);
  // INICIO VACÍO: Se requiere carga de archivo o sync
  const [products, setProducts] = useState<Product[]>([]); 
  const [cart, setCart] = useState<CartItem[]>([]);
  const [selectedCategory, setSelectedCategory] = useState<Category>('All');
  const [searchQuery, setSearchQuery] = useState('');
  const [inStockOnly, setInStockOnly] = useState(false);
  const [currentView, setCurrentView] = useState<AppView>('CATALOG');
  const [activeProduct, setActiveProduct] = useState<Product | null>(null);

  const filteredProducts = useMemo(() => {
    return products.filter(p => {
      const matchesCategory = selectedCategory === 'All' || p.type === selectedCategory;
      const matchesSearch = p.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
                           p.variants.some(v => v.sku.toLowerCase().includes(searchQuery.toLowerCase()));
      const matchesStock = inStockOnly ? !p.isOutOfStock : true;
      return matchesCategory && matchesSearch && matchesStock;
    });
  }, [products, selectedCategory, searchQuery, inStockOnly]);

  const cartTotal = cart.reduce((acc, curr) => acc + (curr.variant.price * curr.quantity), 0);
  const cartCount = cart.reduce((acc, curr) => acc + curr.quantity, 0);

  const handleLogin = (u: User) => {
    setUser(u);
    setCurrentView('CATALOG');
  };

  const handleProductSelect = (p: Product) => {
    setActiveProduct(p);
    setCurrentView('PRODUCT_DETAIL');
  };

  const handleAddToCart = (product: Product, variantSku: string, quantity: number) => {
    const variant = product.variants.find(v => v.sku === variantSku)!;
    setCart(prev => {
      const existingIndex = prev.findIndex(item => item.variant.sku === variantSku);
      if (existingIndex > -1) {
        const newCart = [...prev];
        newCart[existingIndex].quantity += quantity;
        return newCart;
      }
      return [...prev, { product, variant, quantity }];
    });
  };

  const removeFromCart = (sku: string) => {
    setCart(prev => prev.filter(item => item.variant.sku !== sku));
  };

  const updateCartQuantity = (sku: string, qty: number) => {
    setCart(prev => prev.map(item => item.variant.sku === sku ? { ...item, quantity: Math.max(1, qty) } : item));
  };

  const navigateTo = (view: AppView) => {
    setCurrentView(view);
    if (view !== 'PRODUCT_DETAIL') setActiveProduct(null);
    window.scrollTo(0,0);
  };

  // Manejadores de Data Source
  const handleDataUpdate = (newProducts: Product[]) => {
    setProducts(newProducts);
    setSelectedCategory('All');
  };

  const handleResetData = () => {
    setProducts(PRODUCTS);
    setSelectedCategory('All');
    alert('Catálogo restaurado a datos de demostración.');
  };

  if (!user) {
    return <Login onLogin={handleLogin} />;
  }

  return (
    <div className="min-h-screen bg-[#F5F5F7] text-[#1D1D1F] flex flex-col font-sans transition-colors duration-200">
      <Navbar 
        user={user} 
        cartCount={cartCount}
        onOpenCart={() => navigateTo('REVIEW_ORDER')}
        onNavigate={navigateTo}
        searchQuery={searchQuery}
        setSearchQuery={setSearchQuery}
      />

      {currentView === 'CATALOG' && (
        <div className="max-w-[1440px] mx-auto px-6 py-8 flex gap-8 w-full h-[calc(100vh-80px)]">
          <Sidebar 
            products={products}
            selectedCategory={selectedCategory} 
            setSelectedCategory={setSelectedCategory} 
            inStockOnly={inStockOnly}
            setInStockOnly={setInStockOnly}
            onDataUpdate={handleDataUpdate}
            onResetData={handleResetData}
          />

          <ProductGrid 
            products={filteredProducts} 
            onSelect={handleProductSelect} 
            selectedCategory={selectedCategory}
            isEmpty={products.length === 0} // Flag para mostrar estado vacío
          />
        </div>
      )}

      {currentView === 'PRODUCT_DETAIL' && activeProduct && (
        <ProductDetailView 
          product={activeProduct} 
          onAddToCart={handleAddToCart}
          onBack={() => navigateTo('CATALOG')}
          onViewOrder={() => navigateTo('REVIEW_ORDER')}
        />
      )}

      {currentView === 'REVIEW_ORDER' && (
        <ReviewOrderView 
          cart={cart} 
          onUpdateQuantity={updateCartQuantity}
          onRemove={removeFromCart}
          onBack={() => navigateTo('CATALOG')}
          onConfirm={() => {
            setCart([]);
            navigateTo('CATALOG');
          }}
        />
      )}

      {currentView === 'ACCOUNT' && (
        <AccountView user={user} onBack={() => navigateTo('CATALOG')} />
      )}

      {currentView === 'CATALOG' && cart.length > 0 && (
        <div className="fixed bottom-8 right-8 z-40 animate-bounce-in">
