import React, { useState, useRef } from 'react';
import { Category, Product } from '../types';

interface SidebarProps {
  products: Product[];
  selectedCategory: Category;
  setSelectedCategory: (c: Category) => void;
  inStockOnly: boolean;
  setInStockOnly: (val: boolean) => void;
  onDataUpdate?: (products: Product[]) => void;
  onResetData?: () => void;
  isOpen?: boolean;
  onClose?: () => void;
}

// Helpers de lectura de archivo
const readFileAsText = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => resolve(e.target?.result as string);
    reader.onerror = (e) => reject(e);
    reader.readAsText(file);
  });
};

const readFileAsArrayBuffer = (file: File): Promise<ArrayBuffer> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => resolve(e.target?.result as ArrayBuffer);
    reader.onerror = (e) => reject(e);
    reader.readAsArrayBuffer(file);
  });
};

const Sidebar: React.FC<SidebarProps> = ({ 
  products, 
  selectedCategory, 
  setSelectedCategory, 
  inStockOnly, 
  setInStockOnly,
  onDataUpdate,
  onResetData,
  isOpen = false,
  onClose
}) => {
  const [sheetUrl, setSheetUrl] = useState('');
  const [loading, setLoading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const types: string[] = Array.from(new Set(products.map(p => p.type))).sort();

  const getIcon = (type: string) => {
    switch (type.toLowerCase()) {
      case 'smartwatches': return 'watch';
      case 'bocinas': return 'speaker';
      case 'básculas': return 'monitor_weight';
      case 'audífonos': return 'headphones';
      case 'teens': return 'face';
      case 'accesorios': return 'widgets';
      case 'hidratación': return 'water_drop';
      case 'termos': return 'water_drop';
      default: return 'label';
    }
  };

  const handleUrlSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!sheetUrl || !onDataUpdate) return;

    setLoading(true);
    try {
      const { fetchProductsFromUrl } = await import('../services/dataService');
      const newProducts = await fetchProductsFromUrl(sheetUrl);
      if (newProducts.length === 0) throw new Error('No se encontraron productos válidos.');
      onDataUpdate(newProducts);
      alert(`Éxito: ${newProducts.length} productos cargados desde URL.`);
    } catch (err) {
      alert('Error: Asegúrate de que el enlace sea un CSV público válido.');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !onDataUpdate) return;

    setLoading(true);
    try {
      let newProducts: Product[] = [];
      const fileName = file.name.toLowerCase();

      // Importación dinámica del servicio
      const { parseCSVToProducts, parseExcelToProducts } = await import('../services/dataService');

      if (fileName.endsWith('.csv')) {
        const text = await readFileAsText(file);
        newProducts = await parseCSVToProducts(text);
      } else if (fileName.endsWith('.xlsx') || fileName.endsWith('.xls')) {
        const buffer = await readFileAsArrayBuffer(file);
        newProducts = parseExcelToProducts(buffer);
      } else {
        throw new Error('Formato no soportado. Usa .csv, .xlsx o .xls');
      }

      if (newProducts.length === 0) throw new Error('El archivo no contiene productos válidos.');

      onDataUpdate(newProducts);
      alert(`Éxito: ${newProducts.length} productos cargados desde archivo.`);
    } catch (err: any) {
      alert(`Error al procesar archivo: ${err.message || 'Formato inválido'}`);
      console.error(err);
    } finally {
      setLoading(false);
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  const handleCategorySelect = (type: Category) => {
    setSelectedCategory(type);
    if (onClose) onClose(); // Cerrar menú en móvil al seleccionar
  };

  const sidebarContent = (
    <div className="flex-1 overflow-y-auto pr-2 custom-scrollbar h-full pb-20 md:pb-0">
      <div className="mb-8">
        <h3 className="text-[10px] md:text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4 px-3">Categorías</h3>
        <ul className="space-y-1">
          <li>
            <button
              onClick={() => handleCategorySelect('All')}
              className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all ${
                selectedCategory === 'All' 
                  ? 'bg-black text-white shadow-md scale-[1.02]' 
                  : 'text-gray-600 hover:bg-white hover:text-black font-medium'
              }`}
            >
              <span className="material-symbols-outlined text-lg">dashboard</span>
              <span className="text-sm">Todo el Catálogo</span>
            </button>
          </li>
          {types.map(type => (
            <li key={type}>
              <button
                onClick={() => handleCategorySelect(type)}
                className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all ${
                  selectedCategory === type 
                    ? 'bg-black text-white shadow-md scale-[1.02]' 
                    : 'text-gray-600 hover:bg-white hover:text-black font-medium'
                }`}
              >
                <span className="material-symbols-outlined text-lg">{getIcon(type)}</span>
                <span className="text-sm">{type}</span>
              </button>
            </li>
          ))}
        </ul>
      </div>

      <div className="mb-8">
        <h3 className="text-[10px] md:text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4 px-3">Filtros</h3>
        <div 
          className="flex items-center gap-3 cursor-pointer group px-3 py-2 bg-white rounded-xl border border-black/5" 
          onClick={() => setInStockOnly(!inStockOnly)}
        >
          <div className={`w-4 h-4 rounded border flex items-center justify-center transition-all ${inStockOnly ? 'bg-black border-black' : 'border-gray-300'}`}>
            {inStockOnly && <span className="material-icons text-[10px] text-white">done</span>}
          </div>
          <label className="text-sm text-gray-600 group-hover:text-black transition-colors cursor-pointer font-medium">Solo en Stock</label>
        </div>
      </div>

      {/* Sección de Administración de Datos */}
      <div className="mb-8 pt-6 border-t border-black/5">
        <h3 className="text-[10px] md:text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4 px-3 flex items-center gap-2">
          <span className="material-icons text-sm">database</span>
          Gestión de Datos
        </h3>

        <form onSubmit={handleUrlSubmit} className="px-3 mb-4">
          <input 
            type="url" 
            placeholder="Google Sheet CSV Link" 
            className="w-full text-[10px] p-2 rounded-lg border border-gray-200 mb-2 bg-white focus:ring-1 focus:ring-black"
            value={sheetUrl}
            onChange={(e) => setSheetUrl(e.target.value)}
          />
          <button 
            type="submit" 
            disabled={loading}
            className="w-full bg-black text-white text-[10px] font-bold py-2 rounded-lg hover:bg-gray-800 disabled:opacity-50 transition-colors"
          >
            {loading ? 'Cargando...' : 'Sincronizar G-Sheet'}
          </button>
        </form>

        <div className="px-3">
           <button 
            onClick={() => fileInputRef.current?.click()}
            disabled={loading}
            className="w-full bg-white border border-gray-200 text-black text-[10px] font-bold py-2 rounded-lg hover:bg-gray-50 disabled:opacity-50 transition-colors mb-2 flex items-center justify-center gap-2"
          >
            {loading ? 'Procesando...' : (
              <>
                <span className="material-icons text-sm">upload_file</span>
                Cargar CSV / Excel
              </>
            )}
          </button>
          <input 
            type="file" 
            accept=".csv, application/vnd.openxmlformats-officedocument.spreadsheetml.sheet, application/vnd.ms-excel" 
            ref={fileInputRef} 
            className="hidden" 
            onChange={handleFileUpload}
          />

          {onResetData && (
            <button 
              onClick={onResetData}
              className="w-full text-red-500 text-[9px] font-bold py-1 hover:underline text-center"
            >
              Restaurar Demo Data
            </button>
          )}
        </div>

        <p className="px-3 mt-3 text-[9px] text-gray-400 leading-tight">
          Soporta: .xlsx, .xls, .csv<br/>
          Formato: Handle, Title, Price, SKU, Inventory, Image.
        </p>
      </div>
    </div>
  );

  return (
    <>
      {/* Desktop Sidebar */}
      <aside className="w-64 flex-shrink-0 hidden lg:flex flex-col sticky top-20 h-[calc(100vh-6rem)]">
        {sidebarContent}
      </aside>

      {/* Mobile Drawer */}
      {isOpen && (
        <div className="fixed inset-0 z-50 lg:hidden flex">
          <div className="fixed inset-0 bg-black/50 backdrop-blur-sm" onClick={onClose} />
          <div className="relative w-80 bg-[#F5F5F7] h-full shadow-2xl p-6 animate-in slide-in-from-left duration-300">
            <div className="flex items-center justify-between mb-6">
               <h2 className="text-lg font-black uppercase tracking-tight">Menú</h2>
               <button onClick={onClose} className="p-2 bg-white rounded-full text-gray-500 hover:text-black">
                 <span className="material-icons">close</span>
               </button>
            </div>
            {sidebarContent}
          </div>
        </div>
      )}
    </>
  );
};

export default Sidebar;

