                            <div className="w-12 h-12 md:w-14 md:h-14 bg-[#F5F5F7] rounded-xl md:rounded-2xl p-2 border border-black/5 shrink-0 flex items-center justify-center shadow-inner">
                              {item.variant.image ? (
                                <img 
                                  src={item.variant.image} 
                                  className="max-h-full object-contain mix-blend-multiply" 
                                  crossOrigin="anonymous" // CRUCIAL para PDF
                                  alt={item.variant.sku}
                                />
                              ) : <span className="material-icons text-xl text-gray-300">image</span>}
                            </div>
                            <div>
                              <div className="text-sm md:text-base font-black text-black uppercase tracking-tight leading-none mb-1 md:mb-2">{item.product.title}</div>
                              <div className="flex items-center gap-3">
                                <span className="text-[9px] md:text-[10px] font-bold text-gray-500 uppercase tracking-widest">{item.variant.option1}</span>
                                <span className="text-gray-300">|</span>
                                <span className="text-[9px] md:text-[10px] font-mono text-black font-black bg-black/5 px-2 py-0.5 rounded-md uppercase whitespace-nowrap">{item.variant.sku}</span>
                              </div>
                            </div>
                          </div>
                        </td>
                        <td className="px-6 md:px-8 py-4 md:py-6">
                          {/* Control de cantidad */}
                          <div className="flex items-center bg-white border border-black/10 rounded-xl h-9 md:h-10 w-24 mx-auto overflow-hidden shadow-inner px-1" data-html2canvas-ignore="true">
                            <button onClick={() => onUpdateQuantity(item.variant.sku, item.quantity - 1)} className="flex-1 hover:bg-gray-100 font-bold text-lg leading-none pb-0.5">-</button>
                            <span className="w-8 text-center font-black text-sm">{item.quantity}</span>
                            <button onClick={() => onUpdateQuantity(item.variant.sku, item.quantity + 1)} className="flex-1 hover:bg-gray-100 font-bold text-lg leading-none pb-0.5">+</button>
                          </div>
                          {/* Solo texto para PDF */}
                          <div className="hidden text-center font-black text-sm" id="pdf-qty-display">
                             {item.quantity} U
                          </div>
                        </td>
                        <td className="px-6 md:px-8 py-4 md:py-6 text-right">
                          <div className="text-lg md:text-xl font-black text-black tracking-tighter">${(item.variant.price * item.quantity).toFixed(2)}</div>
                          <button 
                            onClick={() => onRemove(item.variant.sku)} 
                            className="text-[8px] text-red-500 font-black uppercase mt-1 md:mt-2 lg:opacity-0 lg:group-hover:opacity-100 transition-opacity underline underline-offset-2"
                            data-html2canvas-ignore="true"
                          >
                            Quitar
                          </button>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          </div>

          {/* Columna Derecha: Resumen */}
          <div className="lg:col-span-4">
            <div className="bg-white rounded-[24px] md:rounded-[32px] border border-black/5 p-6 md:p-10 lg:sticky lg:top-20 shadow-xl shadow-black/5">
              <div className="flex items-center justify-center mb-6">
                  <div className="w-10 h-10 md:w-12 md:h-12 bg-black text-white rounded-xl flex items-center justify-center">
                    <span className="material-icons">layers</span>
                  </div>
              </div>
              <h2 className="text-[10px] font-black text-black uppercase tracking-[0.4em] mb-8 md:mb-10 border-b border-black/5 pb-6 text-center">Resumen B2B</h2>

              <div className="space-y-4 md:space-y-6 mb-8 md:mb-10">
                <div className="flex justify-between text-[10px] font-black uppercase tracking-widest text-gray-400">
                  <span>Artículos</span>
                  <span className="text-black">{totalUnits} Unidades</span>
                </div>
                <div className="flex justify-between text-[10px] font-black uppercase tracking-widest text-gray-400">
                  <span>Subtotal</span>
                  <span className="text-black">${subtotal.toFixed(2)}</span>
                </div>
                <div className="flex justify-between text-[10px] font-black uppercase tracking-widest text-gray-400">
                  <span>ITBMS (7%)</span>
                  <span className="text-black">${tax.toFixed(2)}</span>
                </div>
                <div className="pt-6 md:pt-8 border-t border-black/5 text-right">
                  <div className="text-[10px] font-black text-gray-400 uppercase tracking-[0.4em] mb-2 md:mb-4">Total Orden</div>
                  <div className="text-4xl md:text-5xl font-black text-black tracking-tighter leading-none">${total.toFixed(2)}</div>
