              </div>

              <div className="space-y-3 md:space-y-4" data-html2canvas-ignore="true">
                <button 
                  onClick={handleWhatsApp}
                  className="w-full h-14 md:h-16 bg-[#25D366] text-white rounded-[16px] md:rounded-[20px] text-[9px] md:text-[10px] font-black uppercase tracking-[0.3em] md:tracking-[0.4em] hover:opacity-90 active:scale-[0.98] transition-all flex items-center justify-center gap-3 md:gap-4 shadow-lg group"
                >
                  <span className="material-icons text-lg md:text-xl group-hover:scale-110 transition-transform">chat</span>
