                >
                  {isGeneratingPdf ? (
                    <span className="material-icons animate-spin text-lg md:text-xl">refresh</span>
                  ) : (
                    <span className="material-icons text-lg md:text-xl group-hover:scale-110 transition-transform">picture_as_pdf</span>
                  )}
                  {isGeneratingPdf ? 'Generando...' : 'Descargar PDF'}
                </button>
              </div>

              <p className="mt-6 md:mt-8 text-[8px] md:text-[9px] text-center text-gray-400 font-bold uppercase tracking-[0.15em] leading-relaxed">
                Documento generado digitalmente.<br/>Sujeto a disponibilidad.
              </p>
