export type AppView = 'LOGIN' | 'CATALOG' | 'PRODUCT_DETAIL' | 'REVIEW_ORDER' | 'ACCOUNT';

import React, { useState, useMemo, useEffect } from 'react';
import { User, Product, CartItem, Category, AppView, Order } from './types';
import { PRODUCTS } from './constants';
import Navbar from './components/Navbar';
import Sidebar from './components/Sidebar';
import ProductGrid from './components/ProductGrid';
import ProductDetailView from './components/ProductDetailView';
import ReviewOrderView from './components/ReviewOrderView';
import AccountView from './components/AccountView';

// Usuario por defecto para saltar login
const DEFAULT_USER: User = {
  id: 'usr_guest',
  companyName: 'Invitado B2B',
  email: 'invitado@cubitt.com',
  authorized: true,
  contractUpdateDate: new Date().toLocaleDateString(),
};

const App: React.FC = () => {
  const [user, setUser] = useState<User | null>(DEFAULT_USER);
  const [products, setProducts] = useState<Product[]>([]); 
  const [cart, setCart] = useState<CartItem[]>([]);
  const [orders, setOrders] = useState<Order[]>([]); // Historial de pedidos
  const [selectedCategory, setSelectedCategory] = useState<Category>('All');
  const [searchQuery, setSearchQuery] = useState('');
  const [inStockOnly, setInStockOnly] = useState(false);
  const [currentView, setCurrentView] = useState<AppView>('CATALOG');
  const [activeProduct, setActiveProduct] = useState<Product | null>(null);

  // Estado para controlar el menú lateral en móviles
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  // Cargar pedidos guardados al iniciar
  useEffect(() => {
    const savedOrders = localStorage.getItem('cubitt_b2b_orders');
    if (savedOrders) {
      try {
        setOrders(JSON.parse(savedOrders));
      } catch (e) {
        console.error('Error loading orders', e);
      }
    }
  }, []);

  const saveOrder = (newOrder: Order) => {
    const updatedOrders = [newOrder, ...orders];
    setOrders(updatedOrders);
    localStorage.setItem('cubitt_b2b_orders', JSON.stringify(updatedOrders));
  };

  const deleteOrder = (orderId: string) => {
    const updatedOrders = orders.filter(o => o.id !== orderId);
    setOrders(updatedOrders);
    localStorage.setItem('cubitt_b2b_orders', JSON.stringify(updatedOrders));
  };

  const filteredProducts = useMemo(() => {
    return products.filter(p => {
      const matchesCategory = selectedCategory === 'All' || p.type === selectedCategory;
      const matchesSearch = p.title.toLowerCase().includes(searchQuery.toLowerCase()) || 
                           p.variants.some(v => v.sku.toLowerCase().includes(searchQuery.toLowerCase()));
      const matchesStock = inStockOnly ? !p.isOutOfStock : true;
      return matchesCategory && matchesSearch && matchesStock;
    });
  }, [products, selectedCategory, searchQuery, inStockOnly]);

  const cartTotal = cart.reduce((acc, curr) => acc + (curr.variant.price * curr.quantity), 0);
  const cartCount = cart.reduce((acc, curr) => acc + curr.quantity, 0);

  const handleProductSelect = (p: Product) => {
    setActiveProduct(p);
    setCurrentView('PRODUCT_DETAIL');
  };

  const handleAddToCart = (product: Product, variantSku: string, quantity: number) => {
    const variant = product.variants.find(v => v.sku === variantSku)!;
    setCart(prev => {
      const existingIndex = prev.findIndex(item => item.variant.sku === variantSku);
      if (existingIndex > -1) {
        const newCart = [...prev];
        newCart[existingIndex].quantity += quantity;
        return newCart;
      }
      return [...prev, { product, variant, quantity }];
    });
  };

  const removeFromCart = (sku: string) => {
    setCart(prev => prev.filter(item => item.variant.sku !== sku));
  };

  const updateCartQuantity = (sku: string, qty: number) => {
    setCart(prev => prev.map(item => item.variant.sku === sku ? { ...item, quantity: Math.max(1, qty) } : item));
  };

  const navigateTo = (view: AppView) => {
    setCurrentView(view);
    if (view !== 'PRODUCT_DETAIL') setActiveProduct(null);
    window.scrollTo(0,0);
    setIsMobileMenuOpen(false);
  };

  // Manejadores de Data Source
  const handleDataUpdate = (newProducts: Product[]) => {
    setProducts(newProducts);
    setSelectedCategory('All');
    setIsMobileMenuOpen(false); // Cerrar menú móvil al cargar datos
  };

  const handleResetData = () => {
    setProducts(PRODUCTS);
    setSelectedCategory('All');
    alert('Catálogo restaurado a datos de demostración.');
    setIsMobileMenuOpen(false);
  };

  if (!user) return null; // Should not happen with DEFAULT_USER

  return (
    <div className="min-h-screen bg-[#F5F5F7] text-[#1D1D1F] flex flex-col font-sans transition-colors duration-200">
      <Navbar 
        user={user} 
        cartCount={cartCount}
        onOpenCart={() => navigateTo('REVIEW_ORDER')}
        onNavigate={navigateTo}
        searchQuery={searchQuery}
        setSearchQuery={setSearchQuery}
        onToggleMobileMenu={() => setIsMobileMenuOpen(true)}
      />

      {currentView === 'CATALOG' && (
        <div className="max-w-[1440px] mx-auto px-4 md:px-6 py-4 md:py-8 flex gap-8 w-full h-[calc(100vh-60px)] md:h-[calc(100vh-80px)]">
          <Sidebar 
            products={products}
            selectedCategory={selectedCategory} 
            setSelectedCategory={setSelectedCategory} 
            inStockOnly={inStockOnly}
            setInStockOnly={setInStockOnly}
            onDataUpdate={handleDataUpdate}
            onResetData={handleResetData}
            isOpen={isMobileMenuOpen}
            onClose={() => setIsMobileMenuOpen(false)}
          />

          <ProductGrid 
            products={filteredProducts} 
            onSelect={handleProductSelect} 
            selectedCategory={selectedCategory}
            isEmpty={products.length === 0} 
          />
        </div>
      )}

      {currentView === 'PRODUCT_DETAIL' && activeProduct && (
        <ProductDetailView 
          product={activeProduct} 
          onAddToCart={handleAddToCart}
          onBack={() => navigateTo('CATALOG')}
          onViewOrder={() => navigateTo('REVIEW_ORDER')}
        />
      )}

      {currentView === 'REVIEW_ORDER' && (
        <ReviewOrderView 
          cart={cart} 
          onUpdateQuantity={updateCartQuantity}
          onRemove={removeFromCart}
          onBack={() => navigateTo('CATALOG')}
          onSaveOrder={saveOrder}
          onConfirm={() => {
            setCart([]);
            navigateTo('CATALOG');
          }}
        />
      )}

      {currentView === 'ACCOUNT' && (
        <AccountView 
          user={user} 
          onBack={() => navigateTo('CATALOG')} 
          orders={orders}
          onDeleteOrder={deleteOrder}
        />
      )}

      {currentView === 'CATALOG' && cart.length > 0 && (
        <div className="fixed bottom-6 right-6 z-40 animate-bounce-in">
          <div 
            onClick={() => navigateTo('REVIEW_ORDER')}
            className="bg-black text-white px-5 py-3 md:px-6 md:py-4 rounded-full shadow-2xl flex items-center gap-4 hover:scale-105 transition-transform cursor-pointer"
          >
            <div className="relative">
              <span className="material-icons text-white text-xl md:text-2xl">shopping_bag</span>
              <span className="absolute -top-1 -right-1 w-3.5 h-3.5 md:w-4 md:h-4 bg-white text-black text-[9px] md:text-[10px] font-bold rounded-full flex items-center justify-center">
                {cartCount}
              </span>
            </div>
            <div className="flex flex-col text-left">
              <span className="text-[9px] uppercase tracking-wider text-gray-300 font-semibold hidden md:block">Current Order</span>
              <span className="text-base md:text-xl font-bold leading-none">${cartTotal.toFixed(2)}</span>
            </div>
            <span className="material-icons text-gray-400 text-lg md:text-xl">chevron_right</span>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { CartItem, Order } from '../types';

interface ReviewOrderViewProps {
  cart: CartItem[];
  onUpdateQuantity: (sku: string, qty: number) => void;
  onRemove: (sku: string) => void;
  onBack: () => void;
  onConfirm: () => void;
  onSaveOrder: (order: Order) => void;
}

const ReviewOrderView: React.FC<ReviewOrderViewProps> = ({ 
  cart, 
  onUpdateQuantity, 
  onRemove, 
  onBack, 
  onConfirm,
  onSaveOrder
}) => {
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);

  // Cálculos financieros
  const subtotal = cart.reduce((acc, curr) => acc + (curr.variant.price * curr.quantity), 0);
  const tax = subtotal * 0.07;
  const total = subtotal + tax;

  // Cálculo de unidades totales
  const totalUnits = cart.reduce((acc, curr) => acc + curr.quantity, 0);

  const buildOrderText = () => {
    const br = "\n";
    let text = `📦 *ORDEN B2B CUBITT PANAMA*${br}${br}`;
    cart.forEach((item, i) => {
      text += `${i+1}. *${item.product.title}*${br}   SKU: \`${item.variant.sku}\` | Cant: ${item.quantity}${br}${br}`;
    });
    text += `*TOTAL FINAL: $${total.toFixed(2)}*${br}${br}ID: ${Date.now().toString().slice(-6)}`;
    return text;
  };

  const handleSaveAndConfirm = () => {
    // Guardar el pedido en historial
    const newOrder: Order = {
      id: `ORD-${Date.now().toString().slice(-6)}`,
      date: new Date().toLocaleDateString('es-PA', { year: 'numeric', month: 'long', day: 'numeric', hour: '2-digit', minute: '2-digit' }),
      items: [...cart],
      subtotal,
      tax,
      total,
      status: 'Pending'
    };
    onSaveOrder(newOrder);
    onConfirm();
  };

  const handleWhatsApp = () => {
    window.open(`https://wa.me/50761541129?text=${encodeURIComponent(buildOrderText())}`, '_blank');
    handleSaveAndConfirm();
  };

  const handleDownloadPDF = async () => {
    setIsGeneratingPdf(true);
    try {
      const element = document.getElementById('apple-receipt-content');
      if (!element) {
        throw new Error('No se encontró el contenido para generar el PDF');
      }

      // Importación dinámica
      const html2pdfModule = await import('html2pdf.js');
      const html2pdf = html2pdfModule.default || html2pdfModule;

      const opt = {
        margin:       0,
        filename:     `Cubitt_Receipt_${Date.now()}.pdf`,
        image:        { type: 'jpeg', quality: 0.98 },
        html2canvas:  { 
          scale: 2, // Mejor resolución
          useCORS: true, 
          allowTaint: true,
          logging: false,
          backgroundColor: '#F5F5F7', // Fondo gris claro Apple
          windowWidth: 800
        },
        jsPDF:        { unit: 'in', format: 'letter', orientation: 'portrait' }
      };

      await html2pdf().set(opt).from(element).save();

      // Guardar automáticamente al descargar PDF
      const newOrder: Order = {
        id: `ORD-${Date.now().toString().slice(-6)}`,
        date: new Date().toLocaleDateString('es-PA', { year: 'numeric', month: 'long', day: 'numeric' }),
        items: [...cart],
        subtotal,
        tax,
        total,
        status: 'Paid' // Asumimos 'pagado' o 'procesado' al descargar invoice
      };
      onSaveOrder(newOrder);
      setTimeout(() => onConfirm(), 2000); // Dar tiempo a que el usuario vea que se descargó

    } catch (error) {
      console.error('Error generando PDF:', error);
      alert('Hubo un error generando el PDF. Intenta de nuevo.');
    } finally {
      setIsGeneratingPdf(false);
    }
  };

  if (cart.length === 0) {
    return (
      <div className="max-w-2xl mx-auto px-4 py-24 text-center">
        <span className="material-icons text-[60px] md:text-[80px] text-gray-200 mb-8">receipt_long</span>
        <h2 className="text-lg md:text-xl font-black uppercase tracking-[0.4em] mb-10">Sin SKUs Cargados</h2>
        <button onClick={onBack} className="bg-black text-white px-8 md:px-10 py-4 rounded-full text-[10px] md:text-xs font-black uppercase tracking-[0.2em] shadow-lg hover:scale-105 transition-all">
          Explorar Catálogo
        </button>
      </div>
    );
  }

  return (
    <div className="max-w-[1280px] mx-auto px-4 md:px-6 py-6 md:py-10 animate-in fade-in duration-500">

      {/* Header Interactivo */}
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-end mb-8 gap-6">
        <div>
          <button onClick={onBack} className="text-[10px] font-black text-gray-400 uppercase tracking-[0.4em] mb-4 flex items-center gap-2 hover:text-black group">
            <span className="material-icons text-base group-hover:-translate-x-1 transition-transform">west</span> Regresar
          </button>
          <h1 className="text-3xl md:text-4xl lg:text-5xl font-black text-black uppercase tracking-tighter leading-none">Mi Proforma</h1>
        </div>

        <div className="w-full lg:w-auto bg-black text-white px-6 md:px-8 py-4 md:py-5 rounded-[20px] md:rounded-[24px] flex items-center justify-between lg:justify-start gap-6 shadow-xl">
          <div className="text-right">
            <div className="text-[9px] font-black uppercase tracking-widest opacity-40 mb-1">Total Unidades</div>
            <div className="text-xl md:text-2xl font-black leading-none">{totalUnits}</div>
          </div>
          <div className="w-px h-10 bg-white/20" />
          <span className="material-icons text-2xl md:text-3xl">inventory</span>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* VISTA EN PANTALLA (Editor) */}
        <div className="lg:col-span-8">
            <div className="bg-white rounded-[24px] md:rounded-[32px] border border-black/5 overflow-hidden shadow-sm">
                <div className="overflow-x-auto">
                <table className="w-full text-left min-w-[700px] md:min-w-0">
                    <thead className="bg-[#F5F5F7] text-[9px] font-black text-gray-400 uppercase tracking-[0.3em] border-b border-black/5">
                    <tr>
                        <th className="px-6 md:px-8 py-4 md:py-6">Producto</th>
                        <th className="px-6 md:px-8 py-4 md:py-6 text-center">Cant</th>
                        <th className="px-6 md:px-8 py-4 md:py-6 text-right">Total</th>
                    </tr>
                    </thead>
                    <tbody className="divide-y divide-black/5">
                    {cart.map(item => (
                        <tr key={item.variant.sku} className="group hover:bg-[#F5F5F7]/40 transition-colors">
                        <td className="px-6 md:px-8 py-4 md:py-6">
                            <div className="flex items-center gap-4">
                            <div className="w-12 h-12 bg-[#F5F5F7] rounded-xl p-2 border border-black/5 flex items-center justify-center">
                                <img src={item.variant.image} className="max-h-full mix-blend-multiply" alt="img" />
                            </div>
                            <div>
                                <div className="text-sm font-black uppercase">{item.product.title}</div>
                                <div className="text-[10px] text-gray-400 font-mono">{item.variant.sku} | {item.variant.option1}</div>
                            </div>
                            </div>
                        </td>
                        <td className="px-6 md:px-8 py-4 md:py-6">
                            <div className="flex items-center bg-white border border-black/10 rounded-xl h-9 w-24 mx-auto shadow-inner px-1">
                            <button onClick={() => onUpdateQuantity(item.variant.sku, item.quantity - 1)} className="flex-1 hover:bg-gray-100 font-bold">-</button>
                            <span className="w-8 text-center font-black text-xs">{item.quantity}</span>
                            <button onClick={() => onUpdateQuantity(item.variant.sku, item.quantity + 1)} className="flex-1 hover:bg-gray-100 font-bold">+</button>
