import React, { useState, useRef } from 'react';
import { Category, Product } from '../types';

interface SidebarProps {
  products: Product[];
  selectedCategory: Category;
  setSelectedCategory: (c: Category) => void;
  inStockOnly: boolean;
  setInStockOnly: (val: boolean) => void;
  onDataUpdate?: (products: Product[]) => void;
  onResetData?: () => void;
  isOpen?: boolean;
  onClose?: () => void;
}

// Helpers de lectura de archivo
const readFileAsText = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => resolve(e.target?.result as string);
    reader.onerror = (e) => reject(e);
    reader.readAsText(file);
  });
};

const readFileAsArrayBuffer = (file: File): Promise<ArrayBuffer> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => resolve(e.target?.result as ArrayBuffer);
    reader.onerror = (e) => reject(e);
    reader.readAsArrayBuffer(file);
  });
};

const Sidebar: React.FC<SidebarProps> = ({ 
  products, 
  selectedCategory, 
  setSelectedCategory, 
  inStockOnly, 
  setInStockOnly,
  onDataUpdate,
  onResetData,
  isOpen = false,
  onClose
}) => {
  const [sheetUrl, setSheetUrl] = useState('');
  const [loading, setLoading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const types: string[] = Array.from<string>(new Set(products.map(p => p.type))).sort();

  const getIcon = (type: string) => {
    switch (type.toLowerCase()) {
      case 'smartwatches': return 'watch';
      case 'bocinas': return 'speaker';
      case 'básculas': return 'monitor_weight';
      case 'audífonos': return 'headphones';
      case 'teens': return 'face';
      case 'accesorios': return 'widgets';
      case 'hidratación': return 'water_drop';
      case 'termos': return 'water_drop';
      default: return 'label';
    }
  };

  const handleUrlSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!sheetUrl || !onDataUpdate) return;

    setLoading(true);
    try {
      const { fetchProductsFromUrl } = await import('../services/dataService');
      const newProducts = await fetchProductsFromUrl(sheetUrl);
      if (newProducts.length === 0) throw new Error('No se encontraron productos válidos.');
      onDataUpdate(newProducts);
      alert(`Éxito: ${newProducts.length} productos cargados desde URL.`);
    } catch (err) {
      alert('Error: Asegúrate de que el enlace sea un CSV público válido.');
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  const handleFileUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file || !onDataUpdate) return;

    setLoading(true);
    try {
      let newProducts: Product[] = [];
      const fileName = file.name.toLowerCase();

      // Importación dinámica del servicio
      const { parseCSVToProducts, parseExcelToProducts } = await import('../services/dataService');

      if (fileName.endsWith('.csv')) {
        const text = await readFileAsText(file);
        newProducts = await parseCSVToProducts(text);
      } else if (fileName.endsWith('.xlsx') || fileName.endsWith('.xls')) {
        const buffer = await readFileAsArrayBuffer(file);
        newProducts = parseExcelToProducts(buffer);
      } else {
        throw new Error('Formato no soportado. Usa .csv, .xlsx o .xls');
      }

      if (newProducts.length === 0) throw new Error('El archivo no contiene productos válidos.');

      onDataUpdate(newProducts);
      alert(`Éxito: ${newProducts.length} productos cargados desde archivo.`);
    } catch (err: any) {
      alert(`Error al procesar archivo: ${err.message || 'Formato inválido'}`);
      console.error(err);
    } finally {
      setLoading(false);
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  const handleCategorySelect = (type: Category) => {
    setSelectedCategory(type);
    if (onClose) onClose(); // Cerrar menú en móvil al seleccionar
  };

  const sidebarContent = (
    <div className="flex-1 overflow-y-auto pr-2 custom-scrollbar h-full pb-20 md:pb-0">
      <div className="mb-8">
        <h3 className="text-[10px] md:text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4 px-3">Categorías</h3>
        <ul className="space-y-1">
          <li>
            <button
              onClick={() => handleCategorySelect('All')}
              className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all ${
                selectedCategory === 'All' 
                  ? 'bg-black text-white shadow-md scale-[1.02]' 
                  : 'text-gray-600 hover:bg-white hover:text-black font-medium'
              }`}
            >
              <span className="material-symbols-outlined text-lg">dashboard</span>
              <span className="text-sm">Todo el Catálogo</span>
            </button>
          </li>
          {types.map(type => (
            <li key={type}>
              <button
                onClick={() => handleCategorySelect(type)}
                className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-xl transition-all ${
                  selectedCategory === type 
                    ? 'bg-black text-white shadow-md scale-[1.02]' 
                    : 'text-gray-600 hover:bg-white hover:text-black font-medium'
                }`}
              >
                <span className="material-symbols-outlined text-lg">{getIcon(type)}</span>
                <span className="text-sm">{type}</span>
              </button>
            </li>
          ))}
        </ul>
      </div>

      <div className="mb-8">
        <h3 className="text-[10px] md:text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4 px-3">Filtros</h3>
        <div 
          className="flex items-center gap-3 cursor-pointer group px-3 py-2 bg-white rounded-xl border border-black/5" 
          onClick={() => setInStockOnly(!inStockOnly)}
        >
          <div className={`w-4 h-4 rounded border flex items-center justify-center transition-all ${inStockOnly ? 'bg-black border-black' : 'border-gray-300'}`}>
            {inStockOnly && <span className="material-icons text-[10px] text-white">done</span>}
          </div>
          <label className="text-sm text-gray-600 group-hover:text-black transition-colors cursor-pointer font-medium">Solo en Stock</label>
        </div>
      </div>

      {/* Sección de Administración de Datos */}
      <div className="mb-8 pt-6 border-t border-black/5">
        <h3 className="text-[10px] md:text-[11px] font-black text-gray-400 uppercase tracking-[0.2em] mb-4 px-3 flex items-center gap-2">
          <span className="material-icons text-sm">database</span>
          Gestión de Datos
        </h3>

        <form onSubmit={handleUrlSubmit} className="px-3 mb-4">
          <input 
            type="url" 
            placeholder="Google Sheet CSV Link" 
            className="w-full text-[10px] p-2 rounded-lg border border-gray-200 mb-2 bg-white focus:ring-1 focus:ring-black"
            value={sheetUrl}
            onChange={(e) => setSheetUrl(e.target.value)}
          />
          <button 
            type="submit" 
            disabled={loading}
            className="w-full bg-black text-white text-[10px] font-bold py-2 rounded-lg hover:bg-gray-800 disabled:opacity-50 transition-colors"
          >
            {loading ? 'Cargando...' : 'Sincronizar G-Sheet'}
          </button>
        </form>

        <div className="px-3">
           <button 
            onClick={() => fileInputRef.current?.click()}
            disabled={loading}
            className="w-full bg-white border border-gray-200 text-black text-[10px] font-bold py-2 rounded-lg hover:bg-gray-50 disabled:opacity-50 transition-colors mb-2 flex items-center justify-center gap-2"
          >
            {loading ? 'Procesando...' : (
              <>
                <span className="material-icons text-sm">upload_file</span>
                Cargar CSV / Excel
              </>
            )}
          </button>
          <input 
            type="file" 
            accept=".csv, application/vnd.openxmlformats-officedocument.spreadsheetml.sheet, application/vnd.ms-excel" 
            ref={fileInputRef} 
            className="hidden" 
            onChange={handleFileUpload}
          />

          {onResetData && (
            <button 
              onClick={onResetData}
              className="w-full text-red-500 text-[9px] font-bold py-1 hover:underline text-center"
            >
              Restaurar Demo Data
            </button>
          )}
        </div>

        <p className="px-3 mt-3 text-[9px] text-gray-400 leading-tight">
          Soporta: .xlsx, .xls, .csv<br/>
          Formato: Handle, Title, Price, SKU, Inventory, Image.
        </p>
      </div>
    </div>
  );

  return (
    <>
      {/* Desktop Sidebar */}
      <aside className="w-64 flex-shrink-0 hidden lg:flex flex-col sticky top-20 h-[calc(100vh-6rem)]">
        {sidebarContent}
      </aside>

      {/* Mobile Drawer */}
      {isOpen && (
        <div className="fixed inset-0 z-50 lg:hidden flex">
          <div className="fixed inset-0 bg-black/50 backdrop-blur-sm" onClick={onClose} />
          <div className="relative w-80 bg-[#F5F5F7] h-full shadow-2xl p-6 animate-in slide-in-from-left duration-300">
            <div className="flex items-center justify-between mb-6">
               <h2 className="text-lg font-black uppercase tracking-tight">Menú</h2>
               <button onClick={onClose} className="p-2 bg-white rounded-full text-gray-500 hover:text-black">
                 <span className="material-icons">close</span>
               </button>
            </div>
            {sidebarContent}
          </div>
        </div>
      )}
    </>
  );
};

export default Sidebar;

import React, { useState } from 'react';
import { CartItem, Order } from '../types';

interface ReviewOrderViewProps {
  cart: CartItem[];
  onUpdateQuantity: (sku: string, qty: number) => void;
  onRemove: (sku: string) => void;
  onBack: () => void;
  onConfirm: () => void;
  onSaveOrder: (order: Order) => void;
}

const ReviewOrderView: React.FC<ReviewOrderViewProps> = ({ 
  cart, 
  onUpdateQuantity, 
  onRemove, 
  onBack, 
  onConfirm,
  onSaveOrder
}) => {
  const [isGeneratingPdf, setIsGeneratingPdf] = useState(false);

  // Cálculos financieros
  const subtotal = cart.reduce((acc, curr) => acc + (curr.variant.price * curr.quantity), 0);
  const tax = subtotal * 0.07;
  const total = subtotal + tax;

  // Cálculo de unidades totales
  const totalUnits = cart.reduce((acc, curr) => acc + curr.quantity, 0);

  const buildOrderText = () => {
    const br = "\n";
    let text = `📦 *ORDEN B2B CUBITT PANAMA*${br}${br}`;
    cart.forEach((item, i) => {
      text += `${i+1}. *${item.product.title}*${br}   SKU: \`${item.variant.sku}\` | Cant: ${item.quantity}${br}${br}`;
    });
    text += `*TOTAL FINAL: $${total.toFixed(2)}*${br}${br}ID: ${Date.now().toString().slice(-6)}`;
    return text;
  };

  const handleSaveAndConfirm = () => {
    // Guardar el pedido en historial como Pendiente (WhatsApp)
    const newOrder: Order = {
      id: `ORD-${Date.now().toString().slice(-6)}`,
      date: new Date().toLocaleDateString('es-PA', { year: 'numeric', month: 'long', day: 'numeric', hour: '2-digit', minute: '2-digit' }),
      items: [...cart],
      subtotal,
      tax,
      total,
      status: 'Pending'
    };
    onSaveOrder(newOrder);
    onConfirm();
  };

  const handleWhatsApp = () => {
    window.open(`https://wa.me/50761541129?text=${encodeURIComponent(buildOrderText())}`, '_blank');
    handleSaveAndConfirm();
  };

  const handleDownloadPDF = async () => {
    setIsGeneratingPdf(true);
    try {
      const element = document.getElementById('apple-receipt-content');
      if (!element) {
        throw new Error('No se encontró el contenido para generar el PDF');
      }

      // Uso de la librería global cargada vía script en index.html
      // @ts-ignore
      const html2pdf = window.html2pdf;

      if (typeof html2pdf !== 'function') {
        throw new Error('La librería PDF no está disponible. Recargue la página.');
      }

      const opt = {
        margin:       0,
        filename:     `Cubitt_Receipt_${Date.now()}.pdf`,
        image:        { type: 'jpeg', quality: 0.98 },
        html2canvas:  { 
          scale: 2, // Alta resolución
          useCORS: true, 
          allowTaint: true,
          logging: false,
          backgroundColor: '#F5F5F7',
          windowWidth: 800
        },
        jsPDF:        { unit: 'in', format: 'letter', orientation: 'portrait' }
      };

      await html2pdf().set(opt).from(element).save();

      // Guardar automáticamente como PAGADO al descargar PDF (Invoice generado)
      const newOrder: Order = {
        id: `ORD-${Date.now().toString().slice(-6)}`,
        date: new Date().toLocaleDateString('es-PA', { year: 'numeric', month: 'long', day: 'numeric', hour: '2-digit', minute: '2-digit' }),
        items: [...cart],
        subtotal,
        tax,
        total,
        status: 'Paid'
      };
      onSaveOrder(newOrder);

      // Pequeño delay para UX
      setTimeout(() => onConfirm(), 1500); 

    } catch (error) {
      console.error('Error generando PDF:', error);
      alert('Hubo un error generando el PDF. Intenta de nuevo.');
    } finally {
      setIsGeneratingPdf(false);
    }
  };

  if (cart.length === 0) {
    return (
      <div className="max-w-2xl mx-auto px-4 py-24 text-center">
        <span className="material-icons text-[60px] md:text-[80px] text-gray-200 mb-8">receipt_long</span>
        <h2 className="text-lg md:text-xl font-black uppercase tracking-[0.4em] mb-10">Sin SKUs Cargados</h2>
        <button onClick={onBack} className="bg-black text-white px-8 md:px-10 py-4 rounded-full text-[10px] md:text-xs font-black uppercase tracking-[0.2em] shadow-lg hover:scale-105 transition-all">
          Explorar Catálogo
        </button>
      </div>
    );
  }

  return (
    <div className="max-w-[1280px] mx-auto px-4 md:px-6 py-6 md:py-10 animate-in fade-in duration-500">

      {/* Header Interactivo */}
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-end mb-8 gap-6">
        <div>
          <button onClick={onBack} className="text-[10px] font-black text-gray-400 uppercase tracking-[0.4em] mb-4 flex items-center gap-2 hover:text-black group">
            <span className="material-icons text-base group-hover:-translate-x-1 transition-transform">west</span> Regresar
          </button>
          <h1 className="text-3xl md:text-4xl lg:text-5xl font-black text-black uppercase tracking-tighter leading-none">Mi Proforma</h1>
        </div>

        <div className="w-full lg:w-auto bg-black text-white px-6 md:px-8 py-4 md:py-5 rounded-[20px] md:rounded-[24px] flex items-center justify-between lg:justify-start gap-6 shadow-xl">
          <div className="text-right">
            <div className="text-[9px] font-black uppercase tracking-widest opacity-40 mb-1">Total Unidades</div>
            <div className="text-xl md:text-2xl font-black leading-none">{totalUnits}</div>
          </div>
          <div className="w-px h-10 bg-white/20" />
          <span className="material-icons text-2xl md:text-3xl">inventory</span>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">

        {/* VISTA EN PANTALLA (Editor) */}
        <div className="lg:col-span-8">
            <div className="bg-white rounded-[24px] md:rounded-[32px] border border-black/5 overflow-hidden shadow-sm">
                <div className="overflow-x-auto">
                <table className="w-full text-left min-w-[700px] md:min-w-0">
                    <thead className="bg-[#F5F5F7] text-[9px] font-black text-gray-400 uppercase tracking-[0.3em] border-b border-black/5">
                    <tr>
                        <th className="px-6 md:px-8 py-4 md:py-6">Producto</th>
                        <th className="px-6 md:px-8 py-4 md:py-6 text-center">Cant</th>
                        <th className="px-6 md:px-8 py-4 md:py-6 text-right">Total</th>
                    </tr>
                    </thead>
                    <tbody className="divide-y divide-black/5">
                    {cart.map(item => (
                        <tr key={item.variant.sku} className="group hover:bg-[#F5F5F7]/40 transition-colors">
                        <td className="px-6 md:px-8 py-4 md:py-6">
                            <div className="flex items-center gap-4">
                            <div className="w-12 h-12 bg-[#F5F5F7] rounded-xl p-2 border border-black/5 flex items-center justify-center">
                                <img src={item.variant.image} className="max-h-full mix-blend-multiply" alt="img" />
                            </div>
                            <div>
                                <div className="text-sm font-black uppercase">{item.product.title}</div>
