            <div className="bg-white rounded-[24px] md:rounded-[32px] border border-black/5 p-6 md:p-10 sticky top-20 shadow-xl">
                <h2 className="text-[10px] font-black uppercase tracking-[0.4em] mb-8 text-center text-gray-400 border-b border-black/5 pb-4">Total a Pagar</h2>
                <div className="text-center mb-8">
                    <span className="text-5xl font-black tracking-tighter">${total.toFixed(2)}</span>
                    <div className="text-[10px] font-bold text-gray-400 mt-2 uppercase tracking-widest">Incluye ITBMS (7%)</div>
