import React, { useState, useMemo } from 'react';
import { Product, CartItem, Variant } from '../types';
import ProductCard from './ProductCard';
import ProductDetailModal from './ProductDetailModal';

interface CatalogViewProps {
  products: Product[];
  cart: CartItem[];
  onUpdateCart: (product: Product, variant: Variant, quantity: number) => void;
  onGoToProforma: () => void;
}

const CatalogView: React.FC<CatalogViewProps> = ({ products, cart, onUpdateCart, onGoToProforma }) => {
  const [activeCategory, setActiveCategory] = useState<string>('Todos');
  const [search, setSearch] = useState('');
  const [selectedProduct, setSelectedProduct] = useState<Product | null>(null);

  // Get unique categories for the filter tabs
  const categories = useMemo(() => {
    const cats = Array.from(new Set(products.map(p => p.category)));
    return ['Todos', ...cats.sort()];
  }, [products]);

  // Filter and Sort
  const processedProducts = useMemo(() => {
    let result = products.filter(p => {
      const matchesCat = activeCategory === 'Todos' || p.category === activeCategory;
      const matchesSearch = p.name.toLowerCase().includes(search.toLowerCase()) || 
                            p.variants.some(v => v.sku.toLowerCase().includes(search.toLowerCase()));
      return matchesCat && matchesSearch;
    });

    // Sort by Price DESC (using the maximum price of the product variants)
    // Most expensive items first
    result.sort((a, b) => {
        const priceA = Math.max(...a.variants.map(v => v.price));
        const priceB = Math.max(...b.variants.map(v => v.price));
        return priceB - priceA;
    });

    return result;
  }, [products, activeCategory, search]);

  // Grouping logic for the view
  const groupedProducts = useMemo(() => {
      const groups: Record<string, Product[]> = {};
      processedProducts.forEach(p => {
          if (!groups[p.category]) groups[p.category] = [];
          groups[p.category].push(p);
      });
      return groups;
  }, [processedProducts]);

  // Sort category keys for display (Alphabetical)
  const sortedGroupKeys = useMemo(() => {
      return Object.keys(groupedProducts).sort();
  }, [groupedProducts]);

  const cartTotalItems = cart.reduce((acc, item) => acc + item.quantity, 0);
  const cartTotalPrice = cart.reduce((acc, item) => acc + (item.price * item.quantity), 0);

  const getQuantityInCart = (variantId: string) => {
      return cart.find(item => item.variantId === variantId)?.quantity || 0;
  };

  return (
    <div className="h-full flex flex-col animate-enter">
      {/* Header & Controls */}
      <div className="pt-6 pb-2 px-8 flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
           <h2 className="text-3xl font-bold text-gray-900">Catálogo</h2>
           <p className="text-gray-500 text-sm">Ordenado por precio (Mayor a Menor)</p>
        </div>

        <div className="flex items-center gap-2 bg-white p-2 rounded-2xl shadow-sm border border-gray-100 flex-1 max-w-md">
            <span className="material-symbols-rounded text-gray-400 pl-2">search</span>
            <input 
                type="text" 
                placeholder="Buscar por nombre o SKU..." 
                className="bg-transparent border-none outline-none w-full text-sm placeholder:text-gray-400"
                value={search}
                onChange={(e) => setSearch(e.target.value)}
            />
        </div>
      </div>

      {/* Categories Tabs */}
      <div className="px-8 py-4 overflow-x-auto no-scrollbar">
        <div className="flex gap-2">
            {categories.map(cat => (
                <button
                    key={cat}
                    onClick={() => setActiveCategory(cat)}
                    className={`
                        px-5 py-2 rounded-full text-sm font-medium whitespace-nowrap transition-all
                        ${activeCategory === cat 
                            ? 'bg-black text-white shadow-md' 
                            : 'bg-white text-gray-600 hover:bg-gray-100 border border-transparent'}
                    `}
                >
                    {cat}
                </button>
            ))}
        </div>
      </div>

      {/* Grid Content */}
      <div className="flex-1 overflow-y-auto px-8 pb-32 pt-2">
        {processedProducts.length === 0 ? (
            <div className="flex flex-col items-center justify-center h-64 text-gray-400">
                <span className="material-symbols-rounded text-4xl mb-2">search_off</span>
                <p>No se encontraron productos</p>
            </div>
        ) : (
            <div className="space-y-10">
                {sortedGroupKeys.map(categoryName => (
                    <div key={categoryName}>
                        {/* Section Title */}
                        <h3 className="text-xl font-bold text-gray-800 mb-5 flex items-center gap-3 border-b border-gray-100 pb-2">
                            {categoryName}
                            <span className="text-xs font-semibold text-gray-500 bg-gray-100 px-2 py-1 rounded-full">
                                {groupedProducts[categoryName].length}
                            </span>
                        </h3>

                        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
                            {groupedProducts[categoryName].map(product => (
                                <ProductCard 
                                    key={product.id}
                                    product={product}
                                    quantityInCart={getQuantityInCart}
                                    onUpdateQuantity={(variant, qty) => onUpdateCart(product, variant, qty)}
                                    onClick={() => setSelectedProduct(product)}
                                />
                            ))}
                        </div>
                    </div>
                ))}
            </div>
        )}
      </div>

      {/* Floating Action Bar (Dock) */}
      <div className="fixed bottom-8 left-1/2 transform -translate-x-1/2 w-[90%] max-w-2xl z-40">
        <div className="glass-panel p-3 rounded-[24px] shadow-2xl flex items-center justify-between pl-6 pr-3">
            <div className="flex flex-col">
                <span className="text-xs text-gray-500 font-semibold uppercase">Total Estimado</span>
                <span className="text-xl font-bold text-gray-900">${cartTotalPrice.toLocaleString()}</span>
            </div>

            <button 
                onClick={onGoToProforma}
                disabled={cartTotalItems === 0}
                className="apple-button bg-blue-600 text-white px-6 py-3 rounded-[18px] font-semibold shadow-lg hover:bg-blue-500 disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2"
            >
                <span>Ver Proforma</span>
                <span className="bg-white/20 px-2 py-0.5 rounded-md text-sm">{cartTotalItems}</span>
                <span className="material-symbols-rounded text-lg">arrow_forward</span>
            </button>
        </div>
      </div>

      {/* Product Detail Modal */}
      <ProductDetailModal 
        product={selectedProduct}
        isOpen={!!selectedProduct}
        onClose={() => setSelectedProduct(null)}
        quantityInCart={getQuantityInCart}
        onUpdateQuantity={onUpdateCart}
      />
    </div>
  );
};

