              className="w-full bg-[#F5F5F7] border-none rounded-xl py-3.5 px-5 text-sm font-medium text-black focus:ring-2 focus:ring-black/5 placeholder-gray-400 transition-all" 
              placeholder="compras@empresa.com" 
